script:
export const meta={name:'pass6-confirm',description:'Pass-6: 2-agent confirmation of the 3 fresh fixes',phases:[{title:'Confirm'}]}
const ROOT='/Users/[REDACTED]/hc-assay'
const FIXES=[{"id": "CV-O-1", "file": "scripts/capture_transcripts.py", "what": "_copy_scrubbed scrubs EVERY text file (decode-strict; binary copied verbatim), not only .jsonl \u2014 closes the .json workflow-transcript PII/secret bypass. Working tree re-scrubbed by the pre-commit hook (0 raw-username occurrences); git history needs filter-repo before publish (documented).", "test": "test_copy_scrubbed_scrubs_non_jsonl_text_files, test_copy_scrubbed_copies_binary_verbatim"}, {"id": "CV-M-1", "file": "src/assay_engine/methodology/confirm.py", "what": "stability_threshold confirm-time default is a None sentinel (was 0.9); locked-wins-else-supplied, fall back to 0.9 only when neither given \u2014 a locked threshold !=0.9 is honored without restating (fixes a follow-on regression of H-001).", "test": "test_locked_stability_threshold_is_honored_without_restating_it (+ existing override-raises test still passes)"}, {"id": "CV-S-1", "file": "src/assay_engine/observability/tracing.py", "what": "ASSAY_TRACING_PORT parsed via _int_env naming the bad var (was bare import-time int()).", "test": "test_tracing_int_env_names_the_bad_var"}]
const V={type:'object',required:['fix_id','appropriate','complete','verdict','reasoning'],properties:{fix_id:{type:'string'},appropriate:{type:'boolean'},complete:{type:'boolean'},verdict:{type:'string',enum:['CONFIRMED','CONCERN']},reasoning:{type:'string'}}}
const pr=(f,n)=>`You are confirmer #${n}, independent. Confirm this fix is BOTH appropriate (correct, no regression, idiomatic) AND complete (the named test DISCRIMINATES — fails if reverted). Read the actual changed file + test at ${ROOT}.\nFix ${f.id} in ${f.file}\nWhat: ${f.what}\nTest(s): ${f.test}\nVerdict CONFIRMED or CONCERN; be specific.`
phase('Confirm')
const r=await pipeline(FIXES,f=>parallel([()=>agent(pr(f,1),{label:'cA:'+f.id,phase:'Confirm',schema:V}),()=>agent(pr(f,2),{label:'cB:'+f.id,phase:'Confirm',schema:V})]),
  (vs,f)=>{const[a,b]=vs.filter(Boolean);return{fix_id:f.id,both_confirmed:a&&b&&a.verdict==='CONFIRMED'&&b.verdict==='CONFIRMED',a:a?{v:a.verdict,why:a.reasoning}:null,b:b?{v:b.verdict,why:b.reasoning}:null}})
const concerns=r.filter(x=>!x.both_confirmed)
log('CONFIRMED '+r.filter(x=>x.both_confirmed).length+'/'+r.length+'; CONCERNS: '+concerns.map(c=>c.fix_id).join(', '))
return {confirmed_count:r.filter(x=>x.both_confirmed).length,total:r.length,concerns,all:r}
